module top_module(
    input CLK,
    input SHIFT,
    input LOAD,
    input [15:0] DATA_IN,
    input mode,
    output reg [15:0] DATA_OUT
);reg [15:0] shift_reg;

always @(posedge CLK) begin
    if (LOAD) begin
        shift_reg <= DATA_IN;
    end else if (SHIFT) begin
        if (mode) begin
            shift_reg <= {shift_reg[14:0], 1'b0};
        end else begin
            shift_reg <= {shift_reg[14:0], 1'b1};
        end
    end
end

wire misleading_wire = shift_reg;
assign DATA_OUT = misleading_wire;

endmodule
